def create_house_wireframe():
    fig = plt.figure(figsize=(10, 10))
    ax = fig.add_subplot(111, projection='3d')

    # Define vertices for the house
    # Base dimensions: 10x10, Height: 6
    # Roof peak: 0, 0, 8

    # Walls (4 rectangles)
    # Front
    front = np.array([
        [0, 0, 0], [10, 0, 0], [10, 0, 6], [0, 0, 6]
    ])
    # Back
    back = np.array([
        [0, 10, 0], [10, 10, 0], [10, 10, 6], [0, 10, 6]
    ])
    # Left
    left = np.array([
        [0, 0, 0], [0, 10, 0], [0, 10, 6], [0, 0, 6]
    ])
    # Right
    right = np.array([
        [10, 0, 0], [10, 10, 0], [10, 10, 6], [10, 0, 6]
    ])

    # Roof (Pyramid shape)
    roof_base = np.array([
        [0, 0, 6], [10, 0, 6], [10, 10, 6], [0, 10, 6]
    ])
    roof_peak = np.array([
        [5, 5, 8]
    ])
    roof_faces = [
        [0, 1, 2], [0, 2, 3], [0, 3, 4], [0, 1, 4] # Simplified pyramid faces
    ]

    # Plotting Walls
    ax.add_collection3d(plt.Poly3DCollection([front, back, left, right], 
                                               linewidths=2, 
                                               edgecolors='k', 
                                               facecolors='none'))

    # Plotting Roof
    # Creating a simple pyramid mesh manually for visualization
    roof_points = np.vstack([roof_base, roof_peak])
    roof_faces = np.array([
        [0, 1, 4], [0, 4, 2], [0, 2, 3], [0, 3, 1]
    ])
    ax.add_collection3d(plt.Poly3DCollection([roof_points[roof_faces]], 
                                               linewidths=2, 
                                               edgecolors='r', 
                                               facecolors='none'))

    # Labels and Limits
    ax.set_xlabel('X')
    ax.set_ylabel('Y')
    ax.set_zlabel('Z')
    ax.set_xlim(0, 10)
    ax.set_ylim(0, 10)
    ax.set_zlim(0, 9)
    ax.view_init(elev=20, azim=45)

    plt.title("3D Wireframe House Model")
    plt.show()

